// claim-office.ts

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
};

type Item = { type: string };
type Step = { op: string; items: Item[] };
type Scenario = { steps: Step[] };

export function runScenario(scenario: unknown): { results: { premium: number }[] } {
  const s = scenario as Scenario;
  const step = s.steps[0];
  const itemsBase = step.items.reduce((sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);
  const policyBase = itemsBase * (1 + FIRST_INSURANCE_SURCHARGE);
  const premium = Math.ceil(policyBase + PROCESSING_FEE);
  return { results: [{ premium }] };
}

